def anti_shuffle(s):
    result = []
    current_word = ''

    for char in s:
        if char == ' ':  # If the character is a space, add the sorted word to the result
            if current_word:
                result.append(''.join(sorted(current_word)))
                current_word = ''  # Reset the current word
            result.append(char)  # Add the space as it is
        else:
            current_word += char  # Append non-space characters to the current word

    # Process any remaining word at the end of the string
    if current_word:
        result.append(''.join(sorted(current_word)))

    return ''.join(result)

def even_odd_palindrome(n):
    """
    Given a positive integer n, return a tuple that has the number of even and odd
    integer palindromes that fall within the range(1, n), inclusive.
    """

    def is_palindrome(num):
        return str(num) == str(num)[::-1]

    even_palindrome_count = 0
    odd_palindrome_count = 0

    for i in range(1, n+1):  # Corrected range to include n
        if is_palindrome(i):
            if i % 2 == 0:
                even_palindrome_count += 1
            else:
                odd_palindrome_count += 1

    return (even_palindrome_count, odd_palindrome_count)

def histogram(test):
    """Given a string representing a space separated lowercase letters, return a dictionary
    of the letter with the most repetition and containing the corresponding count.
    If several letters have the same occurrence, return all of them.

    Example:
    histogram('a b c') == {'a': 1, 'b': 1, 'c': 1}
    histogram('a b b a') == {'a': 2, 'b': 2}
    histogram('a b c a b') == {'a': 2, 'b': 2}
    histogram('b b b b a') == {'b': 4}
    histogram('') == {}

    """
    if not test:
        return {}

    # Dictionary to store the frequency of each letter
    freq_dict = {}
    for char in test.split():
        if char:  # Ensure it's not an empty string
            freq_dict[char] = freq_dict.get(char, 0) + 1

    # Find the maximum frequency
    max_freq = max(freq_dict.values())

    # Collect all letters that have the maximum frequency
    result = {char: freq for char, freq in freq_dict.items() if freq == max_freq}

    return result

def get_odd_collatz(n):
    """
    Given a positive integer n, return a sorted list that has the odd numbers in collatz sequence.

    The Collatz conjecture is a conjecture in mathematics that concerns a sequence defined
    as follows: start with any positive integer n. Then each term is obtained from the 
    previous term as follows: if the previous term is even, the next term is one half of 
    the previous term. If the previous term is odd, the next term is 3 times the previous
    term plus 1. The conjecture is that no matter what value of n, the sequence will always reach 1.

    Note: 
        1. Collatz(1) is [1].
        2. returned list sorted in increasing order.

    For example:
    get_odd_collatz(5) returns [1, 5] # The collatz sequence for 5 is [5, 16, 8, 4, 2, 1], so the odd numbers are only 1, and 5.
    """
    if n % 2 == 0:
        odd_collatz = [] 
    else:
        odd_collatz = [n]

    while n > 1:
        if n % 2 == 0:
            n = n / 2
        else:
            n = n * 3 + 1

        if n % 2 == 1 and n not in odd_collatz:
            odd_collatz.append(int(n))

    return sorted(odd_collatz)

def split_words(txt):
    '''
    Given a string of words, return a list of words split on whitespace, if no whitespaces exists in the text you
    should split on commas ',' if no commas exists you should return the number of lower-case letters with odd order in the
    alphabet, ord('a') = 0, ord('b') = 1, ... ord('z') = 25
    Examples
    split_words("Hello world!") ➞ ["Hello", "world!"]
    split_words("Hello,world!") ➞ ["Hello", "world!"]
    split_words("abcdef") == 3 
    '''

    if " " in txt:
        return txt.split()
    elif "," in txt:
        return txt.replace(',', ' ').split()
    else:
        # Count lowercase letters with odd ASCII values
        return len([i for i in txt if i.islower() and (ord(i) - ord('a')) % 2 == 1])

def order_by_points(nums):
    def digits_sum(n):
        # Calculate the sum of digits, treating the first digit as positive if negative
        neg = 1
        if n < 0:
            n, neg = -n, -1
        n = [int(i) for i in str(n)]
        n[0] *= neg
        return sum(n)

    # Sort the list using the custom digits_sum function as the key
    return sorted(nums, key=lambda x: (digits_sum(x), nums.index(x)))

def x_or_y(n, x, y):
    """A simple program which should return the value of x if n is 
    a prime number and should return the value of y otherwise.

    Examples:
    for x_or_y(7, 34, 12) == 34
    for x_or_y(15, 8, 5) == 5

    """
    if n <= 1:
        return y
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return y
    else:
        return x

def compare(game, guess):
    if len(game) != len(guess):
        raise ValueError("The lengths of game and guess must be equal.")

    return [abs(x - y) for x, y in zip(game, guess)]

def even_odd_count(num):
    """Given an integer. return a tuple that has the number of even and odd digits respectively.

     Example:
        even_odd_count(-12) ==> (1, 1)
        even_odd_count(123) ==> (1, 2)
    """
    even_count = 0
    odd_count = 0
    for i in str(abs(num)):
        if int(i) % 2 == 0:
            even_count += 1
        else:
            odd_count += 1
    return (even_count, odd_count)
